//
import { NUMERIC_DATATYPE } from '../core/datatype-constants';
import { Scale } from './scale-component';
import { Registry } from '../core/zc-registry';
import { mathMin, UNDEFINED } from '../core/zc-constants';
import { isArray } from '../utils/zcutils';
import { isHeatMapChartType } from '../events/events-utils';
import { getLegendBound } from '../legend/legend-bound';
import { _legendType } from '../legend/legend-renderer-helpers';
import { convertNull } from '../core/data-processor/size/convert-null';
import { sizeRange } from './range/size-range';
import { sizeCorrection } from '../scale-parser/legend/size/size-correction';
import { generateRanges } from '../scale-parser/legend/size/helper/size-ranges-creation';

class sizeScale extends Scale {
    init() {
        super.init();

        this.d3_scale.clamp = true;

        // default base
        let config = this.getConfig(),
            baseValue = config.base,
            chartObj = this.chartObj,
            _domain = this.schema.domain,
            { ranges } = _domain,
            schema = this.schema;

        if (ranges && ranges._dummy) {
            _domain.ranges = null;
        }

        if (this.schema.data.dataType === NUMERIC_DATATYPE) {
            if (!chartObj.isGeoMap) {
                this.schema.domain.base = baseValue !== UNDEFINED ? baseValue : 0;
            }

            //Remove---
            if (chartObj.systemConf.legend.singleLayout) {
                schema.data.source = () => chartObj.dataObject.getMinMaxZ();
                schema.data.condition = null;
                schema.domain.key = [0, 1];
            }
            //---Remove
        }

        let key = schema.domain.key,
            nullAsOptions = { config, columnKey: chartObj.dataset.getColumnIdx('z') },
            _keyFunction = _key => {
                return d => {
                    let val = d[_key];
                    val = convertNull(val, nullAsOptions);
                    return val;
                };
            };
        schema.domain.key = isArray(key) ? key.map(_keyFunction) : _keyFunction(key);
    }

    create() {
        let scale = super.create(),
            { config, schema } = this,
            encode = 'z',
            view = _legendType(encode, { config, dataType: schema.data.dataType }),
            newRanges = generateRanges(config, schema, scale, view);

        if (newRanges) {
            config.ranges = newRanges;
            schema.domain.ranges = newRanges;
            scale = super.create();
        }

        return (this.scale = scale);
    }

    parseRange(customMax) {
        let chartObj = this.chartObj,
            dim = _getDimension(chartObj),
            config = this.getConfig(),
            bound = getLegendBound(config, chartObj.chartarea, customMax);

        let options = { dim, bound, correction: sizeCorrection };
        return sizeRange.call(this, options);
    }
}

function _getDimension(chartObj) {
    if (_isMatrix(chartObj)) {
        return 1;
    }

    let plotarea = chartObj.plotarea;
    return mathMin(plotarea.width, plotarea.height);
}

function _isMatrix(chartObj) {
    let chartType = chartObj.chartTypes[0].value;
    return isHeatMapChartType(chartType);
}

export { sizeScale };
Registry.setComponent('sizeScale', sizeScale);
